    center: {skyTop:'#18204a', skyMid:'#364f78', skyLow:'#7a5177', ground:'#201527', cloudA:'#fff4d832', cloudB:'#df57742a', wash:'#ffd36e0b', block:'#302d4d', window:'#5fd0e83a', sign:'#CENTER LIGHT: climb bright routes, keep the storm behind.'},
    playground: {skyTop:'#16314a', skyMid:'#3d637c', skyLow:'#7a6856', ground:'#1a1f25', cloudA:'#fff4d83a', cloudB:'#5fd0e82c', wash:'#fff4d80a', block:'#313d45', window:'#ffd36e34', sign:'#PLAY STRUCTURE: height gives time, clouds unlock the gate.'},
    waterfront: {skyTop:'#102846', skyMid:'#23547a', skyLow:'#4f6f7c', ground:'#10202c', cloudA:'#fff4d830', cloudB:'#5fd0e83a', wash:'#5fd0e812', block:'#26394b', window:'#ffd36e2e', sign:'#WATERFRONT WIND: use updrafts before the stormline closes.'},
