  function drawLocationProps(){
    if(drawWorldArtLocationProps(.9)) return;
    const drawProps = LOCATION_PROP_DRAWERS[levelTheme];
    if(drawProps) drawProps();
  }

  function worldPropReady(){
    return !!(worldPropImg && worldPropImg.ready);
  }

  function drawWorldPropFrame(name,x,y,w=128,h=128,alpha=1){
    const f = WORLD_PROP_FRAMES[name];
    if(!f || !worldPropReady()) return false;
    ctx.save();
    ctx.globalAlpha *= alpha;
    ctx.drawImage(worldPropImg, f[0], f[1], 128, 128, Math.round(x), Math.round(y), Math.round(w), Math.round(h));
    ctx.restore();
    return true;
  }

  function drawWorldArtLocationProps(alpha=1){
    if(!worldPropReady()) return false;
    const theme = ['playground'].includes(levelTheme) ? 'center'
      : ['pier'].includes(levelTheme) ? 'waterfront'
      : ['bonus','moonbonus'].includes(levelTheme) ? 'gasworks'
      : levelTheme === 'boss' ? 'fremont'
      : levelTheme;
    ctx.save();
    ctx.globalAlpha = alpha;
    if(theme === 'market'){
      for(let i=0;i<10;i++) drawWorldPropFrame('market', i*560+130, 316, 250, 160, 1);
    } else if(theme === 'center'){
      for(let i=0;i<7;i++) drawWorldPropFrame('center', i*700+190, 236, 230, 210, 1);
    } else if(theme === 'waterfront'){
      for(let i=0;i<11;i++) drawWorldPropFrame('waterfront', i*420+76, 324, 230, 150, 1);
    } else if(theme === 'gasworks'){
      for(let i=0;i<8;i++) drawWorldPropFrame('gasworks', i*620+122, 276, 250, 190, 1);
    } else if(theme === 'fremont'){
      for(let i=0;i<8;i++) drawWorldPropFrame('fremont', i*650+185, 258, 300, 190, 1);
    } else if(theme === 'monorail'){
      for(let i=0;i<7;i++) drawWorldPropFrame('monorail', i*760+120, 238, 330, 190, 1);
    } else {
      ctx.restore();
      return false;
    }
    ctx.restore();
    return true;
  }

