      ctx.fillStyle='#241a28';
      ctx.fillRect(4 + doorSwing*12,40,22,14);
      ctx.strokeStyle='#20151e'; ctx.lineWidth=3; ctx.strokeRect(-2 + doorSwing*12,10,34,52);
      ctx.restore();
