    ctx.fillStyle='#6b6f70';
    ctx.fillRect(x+136,y+38,32,20);
    ctx.fillStyle='#f4f1df';
    ctx.fillRect(x+20,y+34,46,10);
    ctx.fillStyle='#343038';
    ctx.fillRect(x+72,y+44,58,30);
    ctx.fillStyle='#d8d8ca';
    ctx.fillRect(x+8,y+68,170,13);
    ctx.fillStyle='#2a2022';
    ctx.beginPath(); ctx.arc(x+46,y+82,18,0,Math.PI*2); ctx.arc(x+142,y+82,18,0,Math.PI*2); ctx.fill();
    ctx.fillStyle='#67636a';
    ctx.beginPath(); ctx.arc(x+46,y+82,8,0,Math.PI*2); ctx.arc(x+142,y+82,8,0,Math.PI*2); ctx.fill();
